  simp [construction_omega, Set.mem_iUnion, not_exists];
  intro i;
  induction i with
  | zero =>
    simp [construction];
    sorry;
  | succ i ih =>
    simp [construction];
    split_ifs with h;
    . rename_i δ hδ;
      by_contra hC;
      have : δ = φ := by grind;
      subst this;
      apply h Γ ((show encode δ = i by sorry) ▸ hΓ) hφ;
    . assumption
    . assumption

