  (χ ➝ φ ∉ T.theory) ∧ (∃ Γ : Finset (Formula _), ↑Γ ⊆ (construction T hT (encode φ)) ∧ Γ.conj ⋏ φ ➝ ξ ∈ T.theory) := by
  simp only [construction_omega, Set.mem_iUnion, not_exists] at hφ;
